// fizzbuzz.ail — A pure AIL program. No LLM calls.
//
// Demonstrates: fn, if/else, for, built-in functions (range, join,
// to_text), the % (modulo) operator, and list building.
//
// This is the program that proves AIL is a real programming language,
// not just an LLM orchestrator. Everything here executes deterministically
// in microseconds with confidence 1.0.
//
// Run:
//   ail run examples/fizzbuzz.ail --input "20" --mock

fn fizzbuzz(n: Number) -> Text {
    if n % 15 == 0 { return "FizzBuzz" }
    if n % 3 == 0 { return "Fizz" }
    if n % 5 == 0 { return "Buzz" }
    return to_text(n)
}

fn fizzbuzz_range(limit: Number) -> Text {
    results = []
    for i in range(1, limit + 1) {
        results = append(results, fizzbuzz(i))
    }
    return join(results, ", ")
}

entry main(limit: Text) {
    n = to_number(limit)
    if n == false {
        n = 15
    }
    return fizzbuzz_range(n)
}

pure fn fib(n: Number) -> Number {
    if n <= 1 { return n }
    return fib(n - 1) + fib(n - 2)
}
entry main(x: Text) {
    results = []
    for i in range(0, 8) {
        results = append(results, to_text(fib(i)))
    }
    return join(results, ", ")
}

pure fn word_count(s: Text) -> Number {
    return length(split(trim(s), " "))
}
entry main(text: Text) {
    return join([to_text(word_count(text)), "단어"], "")
}

intent classify_sentiment(text: Text) -> Text {
    goal: positive_or_negative_or_neutral
}
entry main(x: Text) {
    return classify_sentiment("I absolutely loved this movie, it was fantastic")
}

intent translate_to_korean(text: Text) -> Text {
    goal: natural Korean translation of the source
}
pure fn titlecase(s: Text) -> Text {
    words = split(s, " ")
    out = []
    for w in words {
        if length(w) > 0 {
            first = upper(slice(w, 0, 1))
            rest = slice(w, 1, length(w))
            out = append(out, join([first, rest], ""))
        }
    }
    return join(out, " ")
}
entry main(text: Text) {
    titled = titlecase(text)
    return join([titled, " -> ", translate_to_korean(titled)], "")
}

// review_analyzer.ail — A realistic hybrid program.
//
// Scenario: you have customer reviews as text (one per line).
// The program:
//   1. Parses lines into individual reviews         (fn — deterministic)
//   2. Filters out empty or too-short reviews       (fn — deterministic)
//   3. Classifies each review's sentiment           (intent — needs LLM)
//   4. Computes summary statistics                  (fn — deterministic)
//   5. Generates a final report                     (fn — deterministic)
//
// This is what "AI-friendly language" means in practice: the AI
// writes fn for what it can compute, intent for what it needs to
// reason about, and the language treats both as first-class.
//
// Run with mock (no API key):
//   ail run examples/review_analyzer.ail \
//       --input "Great product!\nTerrible quality\nLoved it\nOkay I guess\nAwful" \
//       --mock
//
// Run with real Claude:
//   python examples/run_live.py --only review_analyzer

import classify from "stdlib/language"
import word_count from "stdlib/utils"

// --- Deterministic data processing (fn) ---

fn parse_reviews(raw: Text) -> Text {
    lines = split(raw, "\n")
    result = []
    for line in lines {
        cleaned = trim(line)
        if is_empty(cleaned) == false {
            result = append(result, cleaned)
        }
    }
    return result
}

fn is_empty(text: Text) -> Boolean {
    return length(trim(text)) == 0
}

fn is_long_enough(text: Text) -> Boolean {
    return word_count(text) >= 2
}

fn filter_short(reviews: Text) -> Text {
    result = []
    for review in reviews {
        if is_long_enough(review) {
            result = append(result, review)
        }
    }
    return result
}

fn count_label(labels: Text, target: Text) -> Number {
    count = 0
    for label in labels {
        if label == target {
            count = count + 1
        }
    }
    return count
}

fn build_report(total: Number, pos: Number, neg: Number, neu: Number) -> Text {
    pos_pct = 0
    neg_pct = 0
    neu_pct = 0
    if total > 0 {
        pos_pct = pos / total * 100
        neg_pct = neg / total * 100
        neu_pct = neu / total * 100
    }
    lines = [
        join(["Review Analysis Report"], ""),
        join(["======================"], ""),
        join(["Total reviews: ", to_text(total)], ""),
        join(["Positive:      ", to_text(pos), " (", to_text(pos_pct), "%)"], ""),
        join(["Negative:      ", to_text(neg), " (", to_text(neg_pct), "%)"], ""),
        join(["Neutral:       ", to_text(neu), " (", to_text(neu_pct), "%)"], "")
    ]
    return join(lines, "\n")
}

// --- The pipeline (entry) ---

entry main(raw_input: Text) {
    // Step 1-2: Parse and filter (pure fn, no LLM)
    reviews = parse_reviews(raw_input)
    filtered = filter_short(reviews)

    // Step 3: Classify each review (intent, LLM needed)
    labels = []
    for review in filtered {
        label = classify(review, "positive_negative_neutral")
        labels = append(labels, label)
    }

    // Step 4-5: Compute stats and build report (pure fn)
    total = length(labels)
    pos = count_label(labels, "positive")
    neg = count_label(labels, "negative")
    neu = total - pos - neg
    report = build_report(total, pos, neg, neu)
    return report
}

// Simplest possible AIL program.
//
// Demonstrates: entry, intent, goal, single model-backed invocation.

intent greet(name: Text) -> Text {
    goal: Text greeting the named person warmly and briefly
    constraints {
        length < 100
    }
}

entry main(name: Text) {
    greeting = greet(name)
    return greeting
}

intent simplify(text: Text) -> Text {
goal: plain English version suitable to a young child
}
entry main(text: Text) { return simplify(text) }

intent fact_or_opinion(text: Text) -> Text {
    goal: the single word fact or opinion
}
entry main(text: Text) { return fact_or_opinion(text) }

intent classify_item(item: Text) -> Text {
    goal: food_vehicle_or_nature
}
pure fn parse_items(s: Text) -> [Text] {
    result = []
    for item in split(s, ",") {
        result = append(result, trim(item))
    }
    return result
}
entry main(x: Text) {
    items = parse_items("apple,car,ocean")
    results = []
    for item in items {
        results = append(results, join([item, ": ", classify_item(item)], ""))
    }
    return join(results, "\n")
}

pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}
entry main(x: Text) { return factorial(7) }

pure fn primary_or_other(color: Text) -> Text {
    return match color {
        "red" => "primary",
        "blue" => "primary",
        "yellow" => "primary",
        _ => "other"
    }
}
entry main(x: Text) { return primary_or_other("green") }

pure fn parse_entries(raw: Text) -> Text {
    entries = []
    for pair in split(raw, ",") {
        parts = split(trim(pair), ":")
        entries = append(entries, parts)
    }
    return entries
}
pure fn grade_line(name: Text, score: Number) -> Text {
    if score >= 80 { return join([name, ": pass"], "") }
    return join([name, ": fail"], "")
}
entry main(x: Text) {
    entries = parse_entries("Alice:85,Bob:92,Charlie:78")
    results = []
    for e in entries {
        name = get(e, 0)
        score = to_number(get(e, 1))
        results = append(results, grade_line(name, score))
    }
    return join(results, ", ")
}

intent classify_sentiment(text: Text) -> Text {
    goal: positive or negative
}
entry main(x: Text) {
    return classify_sentiment("Terrible quality, broke after one day")
}

pure fn sort_words(text: Text) -> Text {
    words = split(text, " ")
    sorted = []
    for w in words {
        inserted = false
        new_sorted = []
        for s in sorted {
            if inserted == false {
                if w < s {
                    new_sorted = append(new_sorted, w)
                    inserted = true
                }
            }
            new_sorted = append(new_sorted, s)
        }
        if inserted == false {
            new_sorted = append(new_sorted, w)
        }
        sorted = new_sorted
    }
    return join(sorted, " ")
}
entry main(x: Text) { return sort_words("banana cherry apple date") }

intent classify_item(item: Text) -> Text {
    goal: fruit or vegetable
}
pure fn split_items(csv: Text) -> Text {
    return split(csv, ",")
}
entry main(x: Text) {
    items = split_items("apple,banana,cherry")
    results = []
    for it in items {
        results = append(results, join([trim(it), ":", classify_item(trim(it))], ""))
    }
    return join(results, " | ")
}

intent define_word(word: Text) -> Text {
    goal: a short definition of the word
}
pure fn longest_word(text: Text) -> Text {
    best = ""
    for w in split(text, " ") {
        if length(w) > length(best) { best = w }
    }
    return best
}
entry main(x: Text) {
    word = longest_word("extraordinary programming capabilities")
    return join([word, " - ", define_word(word)], "")
}

pure fn word_count(s: Text) -> Number {
    return length(split(trim(s), " "))
}
entry main(x: Text) { return word_count("a b c d e f g h") }

intent detect_language(text: Text) -> Text {
    goal: the language name in English
}
entry main(text: Text) { return detect_language(text) }

pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    out = ""
    for i in range(0, length(chars)) {
        out = join([out, get(chars, length(chars) - 1 - i)], "")
    }
    return out
}
pure fn is_palindrome(s: Text) -> Boolean {
    return lower(s) == reverse_text(lower(s))
}
entry main(x: Text) { if is_palindrome("hello") { return "yes" } return "no" }

pure fn gcd(a: Number, b: Number) -> Number {
    if b == 0 { return a }
    return gcd(b, a % b)
}
entry main(x: Text) { return gcd(48, 18) }

intent topic_of(text: Text) -> Text {
    goal: the primary topic of the source in Korean
}
entry main(x: Text) { return topic_of("한국은행이 기준금리를 0.25%p 인상했다") }

