}
entry main(x: Text) {
    return compose_subject("Q3 budget review meeting")
}

pure fn f_to_c(f: Number) -> Number {
    return round((f - 32) * 5 / 9, 1)
}
entry main(x: Text) { return f_to_c(98.6) }

pure fn sum_list(xs: List[Number]) -> Number {
    total = 0
    for x in xs { total = total + x }
    return total
}
pure fn stddev(xs: List[Number]) -> Number {
    n = length(xs)
    mean = sum_list(xs) / n
    sq_diff = 0
    for x in xs { sq_diff = sq_diff + pow(x - mean, 2) }
    return round(sqrt(sq_diff / n), 3)
}
entry main(x: Text) { return stddev([2, 4, 4, 4, 5, 5, 7, 9]) }

intent even_or_odd(summary: Text) -> Text { goal: even or odd }
pure fn digit_sum(n: Number) -> Number {
    total = 0
    cur = n
    for i in range(0, 20) {
        if cur == 0 { return total }
        total = total + cur % 10
        cur = (cur - cur % 10) / 10
    }
    return total
}
entry main(x: Text) {
    s = digit_sum(127)
    summary = join(["digit sum ", to_text(s)], "")
    return join([summary, " - ", even_or_odd(summary)], "")
}

intent classify_sentiment(text: Text) -> Text {
    goal: sentiment as positive or negative or neutral
}
pure fn word_count(text: Text) -> Number {
    return length(split(text, " "))
}
entry main(text: Text) {
    n = word_count(text)
    s = classify_sentiment(text)
    return join([to_text(n), " words, ", s], "")
}

intent health_comment(bmi: Number) -> Text {
    goal: a short health comment based on the BMI value
}
pure fn compute_bmi(h_cm: Number, w_kg: Number) -> Number {
    return round(w_kg / pow(h_cm / 100, 2), 2)
}
entry main(x: Text) {
    b = compute_bmi(175, 70)
    return join([to_text(b), " — ", health_comment(b)], "")
}

intent describe_performance(avg: Number) -> Text {
    goal: brief natural-language performance summary
}
pure fn avg(xs: List[Number]) -> Number {
    total = 0
    for x in xs { total = total + x }
    return round(total / length(xs), 2)
}
entry main(x: Text) {
    a = avg([72, 85, 90, 68, 77])
    return join([to_text(a), ": ", describe_performance(a)], "")
}

pure fn long_words(text: Text, min_len: Number) -> Number {
    count = 0
    for w in split(text, " ") {
        if length(w) > min_len { count = count + 1 }
    }
    return count
}
entry main(x: Text) {
    return long_words("the quick brown fox jumps over the lazy dog", 3)
}

intent classify_sentiment(text: Text) -> Text {
    goal: positive_or_negative_or_neutral
}
entry main(text: Text) {
    return match classify_sentiment(text) {
        "positive" with confidence > 0.8 => "strong positive",
        "negative" with confidence > 0.8 => "strong negative",
        _ with confidence > 0.6 => "somewhat uncertain",
        _ => "too uncertain to say"
