intent explain_golden_ratio(summary: Text) -> Text {
    goal: one sentence about why the golden ratio appears
}
pure fn fib_n(n: Number) -> Number {
    out = []
    a = 0
    b = 1
    for i in range(0, n) {
        out = append(out, a)
        next_val = a + b
        a = b
        b = next_val
    }
    return out
}
entry main(x: Text) {
    seq = fib_n(8)
    summary = join(["fib: ", to_text(seq)], "")
    return join([summary, " - ", explain_golden_ratio(summary)], "")
}

pure fn only_even(xs: List[Number]) -> List[Number] {
    out = []
