pure fn mean(nums: Number) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}
pure fn stddev(nums: Number) -> Number {
    m = mean(nums)
    total_sq = 0
    for n in nums {
        diff = n - m
        total_sq = total_sq + diff * diff
    }
    variance = total_sq / length(nums)
    // crude integer sqrt by bisection
    lo = 0
    hi = variance + 1
    for step in range(0, 30) {
        mid = (lo + hi) / 2
        if mid * mid > variance { hi = mid } else { lo = mid }
    }
    return lo
}
