pure fn freq(s: Text) -> Text {
    keys = []
    counts = []
    for c in split(s, "") {
        if c in keys {
            new_counts = []
            i = 0
            for k in keys {
                if k == c {
                    new_counts = append(new_counts, get(counts, i) + 1)
                } else {
                    new_counts = append(new_counts, get(counts, i))
                }
                i = i + 1
            }
            counts = new_counts
        } else {
            keys = append(keys, c)
            counts = append(counts, 1)
        }
    }
    parts = []
    i = 0
    for k in keys {
        parts = append(parts, join([k, ":", to_text(get(counts, i))], ""))
        i = i + 1
    }
    return join(parts, ", ")
}
entry main(x: Text) {
    pattern = freq("hello world")
    return join([pattern, " - ", describe_pattern(pattern)], "")
}

