// Translation example demonstrating context inheritance and override.
//
// Shows:
//   - Context declarations with `extends`
//   - `override` keyword on a field
//   - `with context` activating a context for an intent call
//   - Intent body with `on_low_confidence` handler

context translation_job extends default {
    preserve: [formatting, proper_nouns, numbers]
    register: "neutral"
}

context formal_korean extends translation_job {
    override register: "formal"
    target_language: "Korean"
    honorific_level: "합니다체"
}

intent translate_document(source: Text) -> Text {
    goal: Text faithfully translating source into context.target_language
    constraints {
        fidelity > 0.85
        preserve_formatting
    }
    on_low_confidence(threshold: 0.7) {
        return source
    }
}

entry main(document: Text) {
    with context formal_korean:
        translated = translate_document(document)
    return translated
}

pure fn tip_rate(rating: Number) -> Number {
    if rating <= 2 { return 0.0 }
    if rating == 3 { return 0.05 }
    if rating == 4 { return 0.10 }
    return 0.15
}
pure fn add_tip(amount: Number, rate: Number) -> Number {
    return amount + amount * rate
}
pure fn split_evenly(total: Number, n: Number) -> Number {
    return total / n
}
intent budget_opinion(per_person: Number) -> Text {
    goal: one Korean line on whether this lunch cost per person is reasonable
}
entry main(x: Text) {
    rate = tip_rate(4)
    with_tip = add_tip(32000, rate)
    per = split_evenly(with_tip, 4)
    op = budget_opinion(per)
    return join([to_text(per), "원/인 — ", op], "")
}

intent explain_percentile(summary: Text) -> Text {
    goal: one short sentence describing where the value sits
}
pure fn sort_desc(nums: Number) -> Number {
    sorted = []
    for n in nums {
        inserted = false
        new_sorted = []
        for s in sorted {
            if inserted == false {
                if n > s {
                    new_sorted = append(new_sorted, n)
                    inserted = true
                }
            }
            new_sorted = append(new_sorted, s)
        }
        if inserted == false { new_sorted = append(new_sorted, n) }
        sorted = new_sorted
    }
    return sorted
}
pure fn position_of(nums: Number, target: Number) -> Number {
    i = 0
    for n in nums {
        if n == target { return i }
        i = i + 1
    }
    return -1
}
entry main(x: Text) {
    sorted = sort_desc([42, 17, 8, 93, 55])
    pos = position_of(sorted, 42)
    summary = join(["42 is at position ", to_text(pos), " of ", to_text(length(sorted))], "")
    return join([summary, " - ", explain_percentile(summary)], "")
}

