intent recommend_item(summary: Text) -> Text {
    goal: one recommendation sentence given the affordable items
}
pure fn parse_products(csv: Text) -> Text {
    entries = []
    for line in split(csv, "\n") {
        parts = split(line, ",")
        if length(parts) == 2 { entries = append(entries, parts) }
    }
    return entries
}
pure fn affordable(entries: Text, budget: Number) -> Text {
    out = []
    for e in entries {
        if to_number(get(e, 1)) <= budget { out = append(out, get(e, 0)) }
    }
    return out
}
entry main(x: Text) {
    products = parse_products("Widget,9.99\nGadget,24.99\nTool,14.50")
    affordable_list = affordable(products, 20)
    summary = join(["affordable: ", join(affordable_list, ", ")], "")
    return join([summary, " - ", recommend_item(summary)], "")
}

